const db = global.get('mysql');
let username = msg.req.body.username
let password = msg.req.body.password
if (username && password) {
    await db.sql("select * from user where username = ?", username)
    .then(res => {
        if (res.length == 0)
            msg.payload = { code: 400, message: "用户名不存在!" };
        else if (res[0].password != password)
            msg.payload = { code: 400, message: "密码错误!" };
        else {
            msg.req.session.user = res[0];
            msg.payload = { code: 200, message: "登录成功!" };
        }
    })
    .catch(err => {
        console.log(err);
        msg.payload = { code: 500, err };
    })
} else
    msg.payload = { code: 500, message: "登录信息不完整!" };
return msg;

