const db = global.get('mysql');
let categoryId =  msg.req.query.categoryId
let sql = "SELECT *,a.id AS aid,a.name AS aname FROM product a, product_detail b WHERE a.id = b.product_id"
if (categoryId) 
    sql = sql + " and  a.category_id = " + categoryId
let lastObj = null;
await db.sql(sql)
    .then(res => {
        let data = [] ;
        for (let i=0;i<res.length;i++){
            //判断是否和前一条记录是同一个商品    
            if (lastObj && lastObj.id == res[i].aid ){
                lastObj.details.push({
                        id : res[i].id,
                        name : res[i].name,
                        image : res[i].image,
                        stock : res[i].stock,
                        price : res[i].price,
                        salePrice : res[i].sale_price, 
                })
            }else{
                let obj = {
                    id : res[i].aid,
                    name : res[i].aname,
                    description : res[i].description,
                    categoryId : res[i].category_id,
                    showIndex : res[i].show_index,
                    details : [{
                        id : res[i].id,
                        name : res[i].name,
                        image : res[i].image,
                        stock : res[i].stock,
                        price : res[i].price,
                        salePrice : res[i].sale_price,
                    }]
                }
                lastObj = obj;
                data.push(obj);
            }
        }
        msg.payload = data;
    }).catch(err => {
        console.log(err);
        msg.payload = { code: 500, err };
    })
return msg;

const db = global.get('mysql');
let id = msg.req.query.id
let sql = "SELECT *,a.id AS aid,a.name AS aname FROM product a, product_detail b WHERE a.id = b.product_id and a.id = ?"
await db.sql(sql, id)
    .then(res => {
        let product;
        for (let i = 0; i < res.length; i++) {
            //判断是否和前一条记录是同一个商品    
            if (i > 0) {
                product.details.push({
                    id: res[i].id,
                    name: res[i].name,
                    image: res[i].image,
                    stock: res[i].stock,
                    price: res[i].price,
                    salePrice: res[i].sale_price,
                })
            } else {
                product = {
                    id: res[i].aid,
                    name: res[i].aname,
                    description: res[i].description,
                    categoryId: res[i].category_id,
                    showIndex: res[i].show_index,
                    details: [{
                        id: res[i].id,
                        name: res[i].name,
                        image: res[i].image,
                        stock: res[i].stock,
                        price: res[i].price,
                        salePrice: res[i].sale_price,
                    }]
                }
            }
        }
        msg.payload = product;
    }).catch(err => {
        console.log(err);
        msg.payload = { code: 500, err }
    })
return msg;
